import React, { useCallback, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { BomLineDto } from '../../../services/sx/models';
import { DocumentFormHeader } from '../../../components/layout';
import { LegacyCodeSuffix } from '../../../components/legacy/LegacyCodeSuffix';
import legacyStyles from '../../../components/legacy/legacyField.module.css';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import { useMesBomPermissions } from '../../../hooks/useMesPermissions';
import { bomPageLabels as labels } from '../../../constants/bomPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import df from '../../../styles/documentForm.module.css';

const emptyLine: BomLineDto = { materialCode: '', materialName: '', unitCode: 'CAI', quantity: 1 };

const emptyForm = {
  productCode: '',
  unitCode: 'CAI',
  quantity: 1,
  effectiveFrom: new Date().toISOString().slice(0, 10),
  effectiveTo: '',
  isActive: true,
  lines: [{ ...emptyLine }],
};

type FieldErrors = {
  productCode?: string;
  lines?: string;
};

const BomFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const perms = useMesBomPermissions();
  const formReadOnly = isEdit && !perms.canUpdate;

  const [form, setForm] = useState(emptyForm);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});
  const [bomCode, setBomCode] = useState('');
  const [legacyCode, setLegacyCode] = useState<string | null>(null);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  const patchFieldError = useCallback((field: keyof FieldErrors, message?: string) => {
    setFieldErrors(prev => {
      if (!message) {
        const next = { ...prev };
        delete next[field];
        return next;
      }
      return { ...prev, [field]: message };
    });
  }, []);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getBom(id)
        .then(b => {
          if (!cancelled) {
            setBomCode(b.code);
            setLegacyCode(b.legacyCode ?? null);
            setForm({
              productCode: b.productCode,
              unitCode: b.unitCode,
              quantity: b.quantity,
              effectiveFrom: b.effectiveFrom.slice(0, 10),
              effectiveTo: b.effectiveTo?.slice(0, 10) ?? '',
              isActive: b.isActive,
              lines: b.lines.length > 0 ? b.lines : [{ ...emptyLine }],
            });
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadFormError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [id, dispatch]);

  const setLine = (idx: number, field: keyof BomLineDto, value: string | number) => {
    patchFieldError('lines');
    setForm(prev => {
      const lines = [...prev.lines];
      lines[idx] = { ...lines[idx], [field]: value };
      return { ...prev, lines };
    });
  };

  const addLine = () => setForm(prev => ({ ...prev, lines: [...prev.lines, { ...emptyLine }] }));

  const removeLine = (idx: number) => {
    if (form.lines.length <= 1) {
      dispatchAppToast(dispatch, { message: labels.minLineWarning, type: 'warning' });
      return;
    }
    setForm(prev => ({ ...prev, lines: prev.lines.filter((_, i) => i !== idx) }));
  };

  const validate = (): boolean => {
    const next: FieldErrors = {};
    if (!isEdit && !form.productCode.trim()) {
      next.productCode = labels.productRequired;
    }
    const lines = form.lines.filter(l => l.materialCode.trim());
    if (lines.length === 0) {
      next.lines = labels.linesRequired;
    }
    setFieldErrors(next);
    if (Object.keys(next).length > 0) {
      const first = document.querySelector('[data-validation-target="true"]');
      first?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return false;
    }
    return true;
  };

  const handleSave = async () => {
    if (!validate()) return;
    const lines = form.lines.filter(l => l.materialCode.trim());
    setSaving(true);
    try {
      if (isEdit && id) {
        await sxService.updateBom(id, {
          quantity: Number(form.quantity),
          effectiveFrom: form.effectiveFrom,
          effectiveTo: form.effectiveTo || undefined,
          isActive: form.isActive,
          lines,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await sxService.createBom({
          productCode: form.productCode.trim(),
          unitCode: form.unitCode.trim() || 'CAI',
          quantity: Number(form.quantity),
          effectiveFrom: form.effectiveFrom,
          effectiveTo: form.effectiveTo || undefined,
          lines,
        });
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      navigate('/sx/bom');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/sx/bom')}
        title={isEdit ? 'Sửa BOM' : 'Tạo BOM'}
        isNew={isNew}
        isReadOnly={formReadOnly || (isNew && !perms.canCreate)}
        saving={saving}
        saveLabel="Tạo BOM"
        saveEditLabel="Lưu thay đổi"
        onSave={
          (isNew ? perms.canCreate : perms.canUpdate) ? handleSave : undefined
        }
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Sản phẩm</h2>
        {isEdit && bomCode ? (
          <div className={df.row4}>
            <div className={df.field}>
              <label className={df.label}>Mã BOM</label>
              <div className={legacyStyles.codeFieldRow}>
                <Input value={bomCode} readOnly disabled />
                {legacyCode ? (
                  <LegacyCodeSuffix value={legacyCode} testId="erp-bom-legacy-code" />
                ) : null}
              </div>
            </div>
          </div>
        ) : null}
        <div className={df.row4}>
          <div className={df.field} data-validation-target={fieldErrors.productCode ? 'true' : undefined}>
            <label className={df.label}>Mã SP *</label>
            <Input
              value={form.productCode}
              onChange={e => {
                patchFieldError('productCode');
                setForm(p => ({ ...p, productCode: e.target.value }));
              }}
              disabled={isEdit}
              error={fieldErrors.productCode}
              required={!isEdit}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>ĐVT</label>
            <Input
              value={form.unitCode}
              onChange={e => setForm(p => ({ ...p, unitCode: e.target.value }))}
              disabled={isEdit}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>SL chuẩn</label>
            <Input
              type="number"
              min={0.01}
              step={0.01}
              value={String(form.quantity)}
              onChange={e => setForm(p => ({ ...p, quantity: Number(e.target.value) }))}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Hiệu lực từ</label>
            <Input
              type="date"
              value={form.effectiveFrom}
              onChange={e => setForm(p => ({ ...p, effectiveFrom: e.target.value }))}
            />
          </div>
        </div>
        {isEdit && (
          <div className={df.row4}>
            <div className={df.field}>
              <label className={df.label}>Hoạt động</label>
              <Select
                value={form.isActive ? 'true' : 'false'}
                onChange={e => setForm(p => ({ ...p, isActive: e.target.value === 'true' }))}
                options={[
                  { value: 'true', label: 'Khả dụng' },
                  { value: 'false', label: 'Ngưng' },
                ]}
              />
            </div>
          </div>
        )}
      </div>
      <div className={df.section} data-validation-target={fieldErrors.lines ? 'true' : undefined}>
        <h2 className={df.sectionTitle}>Vật tư / NVL</h2>
        {fieldErrors.lines ? (
          <div className={df.errorBanner} role="alert">{fieldErrors.lines}</div>
        ) : null}
        <div className={df.tableWrapper}>
          <table className={df.linesTable}>
            <thead>
              <tr>
                <MaterialLineTableHeaders />
                <th>ĐVT</th>
                <th className={df.thAmount}>SL</th>
                <th className={df.thDel} />
              </tr>
            </thead>
            <tbody>
              {form.lines.map((line, idx) => (
                <tr key={idx}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    onSelect={m => {
                      patchFieldError('lines');
                      setForm(prev => {
                        const lines = [...prev.lines];
                        lines[idx] = {
                          ...lines[idx],
                          materialCode: m.code,
                          materialName: m.name,
                          unitCode: m.unitCode ?? lines[idx].unitCode,
                        };
                        return { ...prev, lines };
                      });
                    }}
                    onClear={() => {
                      setForm(prev => {
                        const lines = [...prev.lines];
                        lines[idx] = { ...lines[idx], materialCode: '', materialName: '' };
                        return { ...prev, lines };
                      });
                    }}
                  />
                  <td>
                    <Input
                      value={line.unitCode}
                      onChange={e => setLine(idx, 'unitCode', e.target.value)}
                    />
                  </td>
                  <td>
                    <Input
                      type="number"
                      min={0.01}
                      value={String(line.quantity)}
                      onChange={e => setLine(idx, 'quantity', Number(e.target.value))}
                    />
                  </td>
                  <td>
                    <button
                      type="button"
                      className={df.btnDeleteLine}
                      onClick={() => removeLine(idx)}
                      title="Xóa dòng"
                    >
                      ×
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <button type="button" className={df.btnAddLine} onClick={addLine}>
          + Thêm dòng
        </button>
      </div>
    </div>
  );
};

export default BomFormPage;
